import React, { useState } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    {
      sender: "bot",
      text: "Hello ЁЯМ▒ IтАЩm really glad you reached out. How are you feeling today?"
    }
  ]);

  const [input, setInput] = useState("");

  const stressSongs = {
    telugu: [
      "Inkem Inkem Inkem Kaavaale тАУ Geetha Govindam",
      "Vintunnava тАУ Ye Maaya Chesave",
      "Samajavaragamana (Soft version)",
      "Yuvathaku Palikina Bhasha"
    ],
    hindi: [
      "Khairiyat тАУ Chhichhore",
      "Agar Tum Saath Ho тАУ Tamasha",
      "Phir Le Aaya Dil (Reprise)",
      "Tu Jaane Na (Soft)"
    ],
    english: [
      "Fix You тАУ Coldplay",
      "Let It Be тАУ The Beatles"
    ]
  };

  const therapistReply = (userText, previousMessages) => {
    const text = userText.toLowerCase().trim();

    const lastBotMessage =
      previousMessages
        .slice()
        .reverse()
        .find((msg) => msg.sender === "bot")?.text.toLowerCase() || "";

    /* ---------- STEP 0: GREETING ONLY ---------- */
    if (["hi", "hello", "hey", "hai"].includes(text)) {
      return "Hello ЁЯЩВ How are you feeling right now?";
    }

    /* ---------- STEP 1: USER EXPRESSES STRESS ---------- */
    if (
      text.includes("stress") ||
      text.includes("stressed") ||
      text.includes("overwhelmed") ||
      text.includes("pressure")
    ) {
      return "Thank you for sharing that ЁЯдН Stress can come from many places. What do you think is causing this stress тАФ studies, work, family, health, money, relationships, future worries, or something else?";
    }

    /* ---------- STEP 2: CAUSE OF STRESS ---------- */
    if (
      text.includes("study") ||
      text.includes("exam") ||
      text.includes("college") ||
      text.includes("work") ||
      text.includes("job") ||
      text.includes("family") ||
      text.includes("money") ||
      text.includes("relationship") ||
      text.includes("future") ||
      text.includes("health") ||
      text.includes("lonely")
    ) {
      return "That sounds really difficult. How long have you been feeling this way тАФ days, weeks, or months?";
    }

    /* ---------- STEP 3: DURATION ---------- */
    if (
      text.includes("days") ||
      text.includes("weeks") ||
      text.includes("months") ||
      text.includes("long time")
    ) {
      return "When stress lasts that long, it can affect both mind and body. How has it been impacting you тАФ sleep, focus, mood, or energy?";
    }

    /* ---------- STEP 4: IMPACT ---------- */
    if (
      text.includes("sleep") ||
      text.includes("tired") ||
      text.includes("focus") ||
      text.includes("anxious") ||
      text.includes("headache") ||
      text.includes("low")
    ) {
      return "I hear you ЁЯШФ YouтАЩve been carrying a lot. Would you like me to suggest something gentle that might help right now, or would you prefer to keep talking?";
    }

    /* ---------- STEP 5: COPING / SOLUTIONS ---------- */
    if (text.includes("suggest") || text.includes("help") || text.includes("yes")) {
      return (
        "Here are a few gentle things that sometimes help with stress:\n\n" +
        "тАв Take slow deep breaths (inhale 4 sec, exhale 6 sec)\n" +
        "тАв Write down whatтАЩs worrying you instead of holding it in\n" +
        "тАв Break problems into very small steps\n" +
        "тАв Rest without guilt тАФ even short breaks matter\n\n" +
        "Would listening to calming music help you right now?"
      );
    }

    /* ---------- STEP 6: MUSIC SUGGESTION ---------- */
    if (text.includes("music") || text.includes("song")) {
      return (
        "Here are some calming songs people often find comforting ЁЯМ┐\n\n" +
        "ЁЯОз Telugu:\n" +
        stressSongs.telugu.join("\n") +
        "\n\nЁЯОз Hindi:\n" +
        stressSongs.hindi.join("\n") +
        "\n\nЁЯОз English:\n" +
        stressSongs.english.join("\n") +
        "\n\nYou can listen quietly and just breathe. IтАЩm still here if you want to talk."
      );
    }

    /* ---------- FALLBACK ---------- */
    return "Thank you for opening up ЁЯМ╝ IтАЩm listening. Can you tell me a little more about what this feels like for you?";
  };

  const handleSend = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };
    const botMessage = {
      sender: "bot",
      text: therapistReply(input, messages)
    };

    setMessages([...messages, userMessage, botMessage]);
    setInput("");
  };

  const handleKeyPress = (e) => {
    if (e.key === "Enter") {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="chat-container">
      <div className="chat-header">
        <h2 className="chat-title">ЁЯТм Professional Therapy Chat</h2>
        <p className="chat-subtitle">A safe space to talk about stress</p>
      </div>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div
            key={index}
            className={`message-group ${
              msg.sender === "user" ? "user-group" : "therapist-group"
            }`}
          >
            <div className="message-label">
              {msg.sender === "user" ? "You" : "Therapist"}
            </div>
            <div className={`message ${msg.sender}`}>
              {msg.text}
            </div>
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type how you're feeling..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyPress={handleKeyPress}
        />
        <button onClick={handleSend}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
